solution_code:
#include <iostream>

template <typename T>
T myMin(T a, T b) {
    return (a < b) ? a : b;
}

int main() {
    int a, b;
    std::cin >> a >> b;
    std::cout << myMin(a, b) << '\n';
    return 0;
}

